  if (body.commit_message) await post('/model-versions/set-tag', {name: name, version: ver, key: 'mlflow.prompt.commit_message', value: body.commit_message});
  await post('/registered-models/alias', {name: name, alias: 'production', version: ver});
  return {action: 'create', name: name, version: ver, status: 'created'};
}

if (action === 'get_or_create') {
  var name = body.name, tmpl = body.template;
  if (!name) throw new Error('name required');
  // Try to get existing
  try {
    var rm = await apiGet('/registered-models/get?name=' + encodeURIComponent(name));
    var modelObj = rm.registered_model;
    var alias = body.alias || 'production';
    var ae = (modelObj.aliases || []).find(function(a) { return a.alias === alias; });
    if (ae) {
      var mvResp = await apiGet('/model-versions/get?name=' + encodeURIComponent(name) + '&version=' + ae.version);
      var mv = mvResp.model_version;
      var vTags = mv.tags || [];
      var pt = vTags.find(function(t) { return t.key === 'mlflow.prompt.text'; });
      var existTmpl = pt ? pt.value : '';
      var vars = [];
      var matches = existTmpl.match(/\{\{\s*\w+\s*\}\}/g);
      if (matches) vars = matches.map(function(x) { return x.replace(/[{}\s]/g, ''); });
      var ct = {};
      vTags.filter(function(t) { return t.key.indexOf('mlflow.') !== 0 && t.key.indexOf('_mlflow') !== 0; }).forEach(function(t) { ct[t.key] = t.value; });
      return {action: 'get_or_create', name: modelObj.name, version: mv.version, alias: alias, template: existTmpl, variables: vars, tags: ct, status: 'existing'};
    }
  } catch(ex) {
    // Not found — fall through to create
  }
  // Create new
  if (!tmpl) throw new Error('template required when creating new prompt');
  await post('/registered-models/create', {name: name});
  await post('/registered-models/set-tag', {name: name, key: 'mlflow.prompt.is_prompt', value: 'true'});
  var tags = body.tags || {};
  for (var k of Object.keys(tags)) await post('/registered-models/set-tag', {name: name, key: k, value: String(tags[k])});
  var mv = await post('/model-versions/create', {name: name, source: 'prompts:/' + name + '/1'});
  var ver = mv.model_version.version;
  await post('/model-versions/set-tag', {name: name, version: ver, key: 'mlflow.prompt.text', value: tmpl});
  if (body.commit_message) await post('/model-versions/set-tag', {name: name, version: ver, key: 'mlflow.prompt.commit_message', value: body.commit_message});
  await post('/registered-models/alias', {name: name, alias: 'production', version: ver});
  return {action: 'get_or_create', name: name, version: ver, status: 'created'};
}

if (action === 'get') {
  var name = body.name;
  if (!name) throw new Error('name required');
  var alias = body.alias || 'production';
  var rm = await apiGet('/registered-models/get?name=' + encodeURIComponent(name));
