  var ae = (modelObj.aliases || []).find(function(a) { return a.alias === alias; });
  if (!ae) throw new Error('Alias ' + alias + ' not found on ' + name);
  // Fix: fetch version directly via model-versions/get
  var mvResp = await apiGet('/model-versions/get?name=' + encodeURIComponent(name) + '&version=' + ae.version);
  var mv = mvResp.model_version;
  var vTags = mv.tags || [];
  var pt = vTags.find(function(t) { return t.key === 'mlflow.prompt.text'; });
  var tmpl = pt ? pt.value : '';
  var vars = [];
  var matches = tmpl.match(/\{\{\s*\w+\s*\}\}/g);
  if (matches) vars = matches.map(function(x) { return x.replace(/[{}\s]/g, ''); });
  var ct = {};
  vTags.filter(function(t) { return t.key.indexOf('mlflow.') !== 0 && t.key.indexOf('_mlflow') !== 0; }).forEach(function(t) { ct[t.key] = t.value; });
  return {action: 'get', name: modelObj.name, version: mv.version, alias: alias, template: tmpl, variables: vars, tags: ct};
}

if (action === 'list') {
  var f = "tags.`mlflow.prompt.is_prompt`='true'";
  var result = await apiGet('/registered-models/search?filter=' + encodeURIComponent(f));
  var prompts = (result.registered_models || []).map(function(rm) {
    var aliases = {};
    (rm.aliases || []).forEach(function(a) { aliases[a.alias] = a.version; });
    var ct = {};
    (rm.tags || []).filter(function(t) { return t.key.indexOf('mlflow.') !== 0 && t.key.indexOf('_mlflow') !== 0; }).forEach(function(t) { ct[t.key] = t.value; });
    return {name: rm.name, aliases: aliases, tags: ct};
  });
  return {action: 'list', count: prompts.length, prompts: prompts};
}

if (action === 'update') {
  var name = body.name, tmpl = body.template;
  if (!name || !tmpl) throw new Error('name and template required');
  var mv = await post('/model-versions/create', {name: name, source: 'prompts:/' + name});
