}

if (action === 'promote') {
  var name = body.name, ver = body.version;
  if (!name || !ver) throw new Error('name and version required');
  var alias = body.alias || 'production';
  // Verify version exists
  await apiGet('/model-versions/get?name=' + encodeURIComponent(name) + '&version=' + ver);
  await post('/registered-models/alias', {name: name, alias: alias, version: String(ver)});
  return {action: 'promote', name: name, version: ver, alias: alias, status: 'promoted'};
}

if (action === 'delete') {
  var name = body.name;
  if (!name) throw new Error('name required');
  if (body.version) {
    // Guard: don't delete the version currently aliased as production
    var rm = await apiGet('/registered-models/get?name=' + encodeURIComponent(name));
    var prodAlias = (rm.registered_model.aliases || []).find(function(a) { return a.alias === 'production'; });
    if (prodAlias && prodAlias.version === String(body.version)) {
      throw new Error('Cannot delete version ' + body.version + ' — it is the current production alias. Re-alias first.');
    }
    await apiDel('/model-versions/delete', {name: name, version: String(body.version)});
    return {action: 'delete', name: name, version: body.version, status: 'version_deleted'};
  }
  await apiDel('/registered-models/delete', {name: name});
  return {action: 'delete', name: name, status: 'deleted'};
}

if (action === 'seed') {
  var prompts = body.prompts;
  if (!prompts || !Array.isArray(prompts)) throw new Error('prompts array required');
  var created = [], skipped = [];
  for (var i = 0; i < prompts.length; i++) {
    var p = prompts[i];
    if (!p.name || !p.template) throw new Error('Each prompt needs name and template');
    try {
      await apiGet('/registered-models/get?name=' + encodeURIComponent(p.name));
      skipped.push(p.name);
    } catch(ex) {
      await post('/registered-models/create', {name: p.name});
      await post('/registered-models/set-tag', {name: p.name, key: 'mlflow.prompt.is_prompt', value: 'true'});
      var seedTags = p.tags || {};
      for (var sk of Object.keys(seedTags)) await post('/registered-models/set-tag', {name: p.name, key: sk, value: String(seedTags[sk])});
      var seedMv = await post('/model-versions/create', {name: p.name, source: 'prompts:/' + p.name + '/1'});
      var seedVer = seedMv.model_version.version;
      await post('/model-versions/set-tag', {name: p.name, version: seedVer, key: 'mlflow.prompt.text', value: p.template});
      if (p.commit_message) await post('/model-versions/set-tag', {name: p.name, version: seedVer, key: 'mlflow.prompt.commit_message', value: p.commit_message});
      await post('/registered-models/alias', {name: p.name, alias: 'production', version: seedVer});
      created.push(p.name);
    }
  }
  return {action: 'seed', created: created, skipped: skipped, count: prompts.length};
}

if (action === 'versions') {
  var name = body.name;
  if (!name) throw new Error('name required');
  var rm = await apiGet('/registered-models/get?name=' + encodeURIComponent(name));
  var modelObj = rm.registered_model;
  var aliasMap = {};
  (modelObj.aliases || []).forEach(function(a) { aliasMap[a.version] = aliasMap[a.version] || []; aliasMap[a.version].push(a.alias); });
  // Find max version from latest_versions
  var maxVer = 0;
  (modelObj.latest_versions || []).forEach(function(lv) { var v = Number(lv.version); if (v > maxVer) maxVer = v; });
  // Also check aliases for higher versions
  (modelObj.aliases || []).forEach(function(a) { var v = Number(a.version); if (v > maxVer) maxVer = v; });
  if (maxVer === 0) maxVer = 1;
  // Fetch each version individually
  var versions = [];
  for (var vi = maxVer; vi >= 1; vi--) {
    try {
      var mvResp = await apiGet('/model-versions/get?name=' + encodeURIComponent(name) + '&version=' + vi);
      var mv = mvResp.model_version;
      var vTags = mv.tags || [];
      var pt = vTags.find(function(t) { return t.key === 'mlflow.prompt.text'; });
      var cm = vTags.find(function(t) { return t.key === 'mlflow.prompt.commit_message'; });
      versions.push({
        version: mv.version,
        template: pt ? pt.value : '',
        commit_message: cm ? cm.value : '',
        aliases: aliasMap[mv.version] || [],
        created_at: Number(mv.creation_timestamp)
      });
    } catch(verErr) { /* version may have been deleted */ }
  }
  return {action: 'versions', name: name, versions: versions, count: versions.length};
}

if (action === 'diff') {
  var name = body.name;
  if (!name || !body.v1 || !body.v2) throw new Error('name, v1, and v2 required');
  var mv1 = await apiGet('/model-versions/get?name=' + encodeURIComponent(name) + '&version=' + body.v1);
  var mv2 = await apiGet('/model-versions/get?name=' + encodeURIComponent(name) + '&version=' + body.v2);
  var t1 = (mv1.model_version.tags || []).find(function(t) { return t.key === 'mlflow.prompt.text'; });
  var t2 = (mv2.model_version.tags || []).find(function(t) { return t.key === 'mlflow.prompt.text'; });
  var tmpl1 = t1 ? t1.value : '';
  var tmpl2 = t2 ? t2.value : '';
  return {action: 'diff', name: name, v1: {version: String(body.v1), template: tmpl1}, v2: {version: String(body.v2), template: tmpl2}, changed: tmpl1 !== tmpl2};
}

if (action === 'set_canary') {
  var name = body.name;
  var stagingVer = body.staging_version;
  var trafficPct = body.traffic_pct;
  if (!name) throw new Error('name required');
  if (!stagingVer) throw new Error('staging_version required');
  if (trafficPct == null || trafficPct < 0 || trafficPct > 100) throw new Error('traffic_pct required (0-100)');
  // Verify staging version exists
  await apiGet('/model-versions/get?name=' + encodeURIComponent(name) + '&version=' + stagingVer);
  // Set staging alias
  await post('/registered-models/alias', {name: name, alias: 'staging', version: String(stagingVer)});
  // Store canary config as tags on registered model
  await post('/registered-models/set-tag', {name: name, key: 'canary.enabled', value: 'true'});
  await post('/registered-models/set-tag', {name: name, key: 'canary.staging_version', value: String(stagingVer)});
  await post('/registered-models/set-tag', {name: name, key: 'canary.traffic_pct', value: String(trafficPct)});
  return {action: 'set_canary', name: name, staging_version: stagingVer, traffic_pct: trafficPct, status: 'canary_set'};
}

if (action === 'get_canary') {
  var name = body.name;
  if (!name) throw new Error('name required');
  var rm = await apiGet('/registered-models/get?name=' + encodeURIComponent(name));
  var modelTags = {};
  (rm.registered_model.tags || []).forEach(function(t) { modelTags[t.key] = t.value; });
  var enabled = modelTags['canary.enabled'] === 'true';
  var aliases = {};
  (rm.registered_model.aliases || []).forEach(function(a) { aliases[a.alias] = a.version; });
  return {
    action: 'get_canary',
    name: name,
    canary_enabled: enabled,
    production_version: aliases['production'] || null,
    staging_version: enabled ? (modelTags['canary.staging_version'] || null) : null,
    traffic_pct: enabled ? Number(modelTags['canary.traffic_pct'] || 0) : 0
  };
}

if (action === 'clear_canary') {
  var name = body.name;
  if (!name) throw new Error('name required');
  await post('/registered-models/set-tag', {name: name, key: 'canary.enabled', value: 'false'});
  await post('/registered-models/set-tag', {name: name, key: 'canary.staging_version', value: ''});
  await post('/registered-models/set-tag', {name: name, key: 'canary.traffic_pct', value: '0'});
  // Remove staging alias
  try { await apiDel('/registered-models/alias', {name: name, alias: 'staging'}); } catch(e) {}
  return {action: 'clear_canary', name: name, status: 'canary_cleared'};
}


if (action === 'pipeline') {
  var name = body.name;
  var stagingVer = body.staging_version;
  var threshold = body.threshold || 0.8;
  var canaryPct = body.canary_pct || 20;
  var autoPromote = body.auto_promote !== false;
  var maxCases = body.limit || 10;

  if (!name) throw new Error('name required (e.g. coder.SYSTEM)');
  if (!stagingVer) throw new Error('staging_version required');

  // Verify staging version exists and get its template
  var stagMvResp = await apiGet('/model-versions/get?name=' + encodeURIComponent(name) + '&version=' + stagingVer);
  var stagTags = stagMvResp.model_version.tags || [];
  var stagTmplTag = stagTags.find(function(t) { return t.key === 'mlflow.prompt.text'; });
  var stagTemplate = stagTmplTag ? stagTmplTag.value : '';

  // Get production template
  var rm = await apiGet('/registered-models/get?name=' + encodeURIComponent(name));
  var prodAlias = (rm.registered_model.aliases || []).find(function(a) { return a.alias === 'production'; });
  if (!prodAlias) throw new Error('No production alias on ' + name);
  var prodMvResp = await apiGet('/model-versions/get?name=' + encodeURIComponent(name) + '&version=' + prodAlias.version);
  var prodTags = prodMvResp.model_version.tags || [];
  var prodTmplTag = prodTags.find(function(t) { return t.key === 'mlflow.prompt.text'; });
  var prodTemplate = prodTmplTag ? prodTmplTag.value : '';

  // Set staging alias
  await post('/registered-models/alias', {name: name, alias: 'staging', version: String(stagingVer)});

  // Determine agent domain for dataset lookup
  var agentDomain = name.replace('.SYSTEM', '');

  // Search for benchmark datasets
  var N8N_SELF = $env.N8N_INTERNAL_URL || 'http://n8n:5678/webhook';
  var selfHeaders = {'Content-Type': 'application/json'};
  if ($env.WEBHOOK_API_KEY) selfHeaders['X-API-Key'] = $env.WEBHOOK_API_KEY;

  var dsResp = await _post(N8N_SELF + '/datasets', {action: 'list'}, {timeout: 15000, headers: selfHeaders});
  var allDatasets = dsResp.data.datasets || [];
  var agentDatasets = allDatasets.filter(function(ds) {
    return ds.name && ds.name.indexOf(agentDomain + '.') === 0;
  });

  if (agentDatasets.length === 0) {
    throw new Error('No benchmark datasets for ' + agentDomain + '. Run: uv run scripts/agent-benchmark.py --seed-datasets');
  }

  // Collect test rows from datasets
  var testRows = [];
  for (var di = 0; di < agentDatasets.length && testRows.length < maxCases; di++) {
    var ds = agentDatasets[di];
    try {
      var rowsResp = await _post(N8N_SELF + '/datasets', {
        action: 'get', run_id: ds.run_id, include_rows: true
      }, {timeout: 30000, headers: selfHeaders});
      var rows = rowsResp.data.rows || [];
      for (var ri = 0; ri < rows.length && testRows.length < maxCases; ri++) {
        testRows.push(rows[ri]);
      }
    } catch(rowErr) { /* skip */ }
  }

  if (testRows.length === 0) {
    throw new Error('No test rows found in datasets for ' + agentDomain);
  }

  // Run each test case against both production and staging templates
  var INFERENCE_BASE = $env.INFERENCE_BASE_URL || 'http://litellm:4000/v1';
  var INFERENCE_KEY = $env.LITELLM_API_KEY || '';
  var llmModel = body.model || $env.INFERENCE_DEFAULT_MODEL || 'qwen2.5:14b';
  var llmHeaders = INFERENCE_KEY ? {Authorization: 'Bearer ' + INFERENCE_KEY} : {};
  var judges = body.judges || ['relevance'];

  var prodScores = [], stagScores = [], failures = [];
  for (var ti = 0; ti < testRows.length; ti++) {
    var row = testRows[ti];
    var userMsg = row.input || '';
    var criteria = row.criteria || 'Response should be relevant and accurate.';

    // Production response
    var prodResp, stagResp;
    try {
      var pr = await _post(INFERENCE_BASE + '/chat/completions', {
        model: llmModel,
        messages: [{role: 'system', content: prodTemplate}, {role: 'user', content: userMsg}],
        temperature: 0
      }, {timeout: 120000, headers: llmHeaders});
      prodResp = pr.data.choices[0].message.content;
    } catch(e) { prodResp = ''; }

    // Staging response
    try {
      var sr = await _post(INFERENCE_BASE + '/chat/completions', {
        model: llmModel,
        messages: [{role: 'system', content: stagTemplate}, {role: 'user', content: userMsg}],
        temperature: 0
      }, {timeout: 120000, headers: llmHeaders});
      stagResp = sr.data.choices[0].message.content;
    } catch(e) { stagResp = ''; }

    // Judge both via eval endpoint
    var prodJudgeScore = 0, stagJudgeScore = 0;
    for (var ji = 0; ji < judges.length; ji++) {
      var judgeName = typeof judges[ji] === 'string' ? judges[ji] : judges[ji].metric;
      // Use inline judging (simple prompt)
      var judgePrompt = 'Score from 0.0 to 1.0. Criteria: ' + criteria + '\n\nInput: ' + userMsg.substring(0, 500) + '\n\nResponse: ';
      try {
        var pjr = await _post(INFERENCE_BASE + '/chat/completions', {
          model: llmModel,
          messages: [{role: 'system', content: 'You are a strict evaluator. Score the response 0.0 to 1.0 based on the criteria. Respond with ONLY JSON: {"score": 0.00, "reason": "brief"}'}, {role: 'user', content: judgePrompt + prodResp.substring(0, 1000)}],
          temperature: 0
        }, {timeout: 60000, headers: llmHeaders});
        var pjText = pjr.data.choices[0].message.content;
        var pjMatch = pjText.match(/\{[^}]*"score"[^}]*\}/);
        if (pjMatch) prodJudgeScore += Math.max(0, Math.min(1, JSON.parse(pjMatch[0]).score || 0));
      } catch(e) {}
      try {
        var sjr = await _post(INFERENCE_BASE + '/chat/completions', {
          model: llmModel,
          messages: [{role: 'system', content: 'You are a strict evaluator. Score the response 0.0 to 1.0 based on the criteria. Respond with ONLY JSON: {"score": 0.00, "reason": "brief"}'}, {role: 'user', content: judgePrompt + stagResp.substring(0, 1000)}],
          temperature: 0
        }, {timeout: 60000, headers: llmHeaders});
        var sjText = sjr.data.choices[0].message.content;
        var sjMatch = sjText.match(/\{[^}]*"score"[^}]*\}/);
        if (sjMatch) stagJudgeScore += Math.max(0, Math.min(1, JSON.parse(sjMatch[0]).score || 0));
      } catch(e) {}
    }

    var prodAvg = judges.length > 0 ? prodJudgeScore / judges.length : 0;
    var stagAvg = judges.length > 0 ? stagJudgeScore / judges.length : 0;
    prodScores.push(prodAvg);
    stagScores.push(stagAvg);
    if (stagAvg < threshold) {
      failures.push({label: (row.domain || '') + '.' + (row.task || '') + '.' + ti, staging_score: stagAvg});
    }
  }

  // Aggregate
  var scoreCount = prodScores.length;
  var prodScore = scoreCount > 0 ? Math.round((prodScores.reduce(function(a,b){return a+b;},0) / scoreCount) * 1000) / 1000 : 0;
  var stagScore = scoreCount > 0 ? Math.round((stagScores.reduce(function(a,b){return a+b;},0) / scoreCount) * 1000) / 1000 : 0;
  var delta = Math.round((stagScore - prodScore) * 1000) / 1000;
  var passRate = scoreCount > 0 ? Math.round(((scoreCount - failures.length) / scoreCount) * 100) / 100 : 0;

  // Gate
  var gatePass = stagScore >= threshold && stagScore >= prodScore;
  var decision;

  if (gatePass && autoPromote) {
    await post('/registered-models/alias', {name: name, alias: 'production', version: String(stagingVer)});
    await post('/registered-models/set-tag', {name: name, key: 'canary.enabled', value: 'false'});
    await post('/registered-models/set-tag', {name: name, key: 'canary.staging_version', value: ''});
    try { await _del(M + '/registered-models/alias', {data: {name: name, alias: 'staging'}}); } catch(e) {}
    try {
      await _post(N8N_SELF + '/traces', {
        action: 'baseline_set_benchmark', prompt_name: name, version: String(stagingVer),
        scores: {overall: stagScore}, pass_rate: passRate, cases_evaluated: scoreCount
      }, {timeout: 15000, headers: selfHeaders});
    } catch(e) {}
    decision = 'promoted';
  } else if (gatePass && !autoPromote) {
    await post('/registered-models/set-tag', {name: name, key: 'canary.enabled', value: 'true'});
    await post('/registered-models/set-tag', {name: name, key: 'canary.staging_version', value: String(stagingVer)});
    await post('/registered-models/set-tag', {name: name, key: 'canary.traffic_pct', value: String(canaryPct)});
    decision = 'canary';
  } else {
    await post('/registered-models/set-tag', {name: name, key: 'canary.enabled', value: 'false'});
    await post('/registered-models/set-tag', {name: name, key: 'canary.staging_version', value: ''});
    decision = 'rejected';
  }

  // Log to promotions experiment
  var promExpName = agentDomain + '-promotions';
  var promExpId;
  try {
    var eres = await apiGet('/experiments/get-by-name?experiment_name=' + encodeURIComponent(promExpName));
    promExpId = eres.experiment.experiment_id;
  } catch(e) {
    var cr = await post('/experiments/create', {name: promExpName});
    promExpId = cr.experiment_id;
  }
  var promTs = Date.now();
  var promRun = await post('/runs/create', {experiment_id: promExpId, start_time: promTs, run_name: 'pipeline-v' + stagingVer + '-' + decision});
  var promRunId = promRun.run.info.run_id;
  await post('/runs/log-batch', {
    run_id: promRunId,
    params: [
      {key: 'agent', value: agentDomain}, {key: 'prompt_name', value: name},
      {key: 'staging_version', value: String(stagingVer)}, {key: 'decision', value: decision},
      {key: 'threshold', value: String(threshold)}
    ],
    metrics: [
      {key: 'production_score', value: prodScore, timestamp: promTs, step: 0},
      {key: 'staging_score', value: stagScore, timestamp: promTs, step: 0},
      {key: 'delta', value: delta, timestamp: promTs, step: 0},
      {key: 'pass_rate', value: passRate, timestamp: promTs, step: 0},
      {key: 'cases_evaluated', value: scoreCount, timestamp: promTs, step: 0}
    ],
    tags: [{key: 'agent', value: agentDomain}, {key: 'decision', value: decision}]
  });
  await post('/runs/update', {run_id: promRunId, status: 'FINISHED', end_time: Date.now()});

  return {
    pipeline: 'promote', name: name, staging_version: Number(stagingVer),
    decision: decision, production_score: prodScore, staging_score: stagScore,
    delta: delta, threshold: threshold, pass_rate: passRate,
    cases_evaluated: scoreCount, experiment_run_id: promRunId,
    evidence: {failures: failures.slice(0, 5)}
  };
}

throw new Error('Unknown action: ' + action);

} catch(e) {
  var msg = e.message || String(e);
  if (e.response && e.response.data) msg += ' | ' + JSON.stringify(e.response.data);
  var status = 400;
  if (e.response && e.response.status === 404) status = 404;
  if (msg.indexOf('RESOURCE_DOES_NOT_EXIST') !== -1) status = 404;
  return {error: true, message: msg, action: action || 'unknown', _status: status};
}
